// 1. Application class тАФ the entry point
@HiltAndroidApp
class MyApp : Application()

// AndroidManifest.xml тАФ <application android:name=".MyApp" ...>

// 2. Domain class тАФ Hilt knows how to build it (has @Inject constructor)
class UserRepository @Inject constructor(
  private val dao: UserDao,     // Hilt will provide these
  private val api: UserApi,
) {
  suspend fun refresh() { dao.upsertAll(api.fetchUsers()) }
}

// 3. Interface with an implementation тАФ use @Binds
interface LogService { fun log(msg: String) }
class LogServiceImpl @Inject constructor() : LogService {
  override fun log(msg: String) = android.util.Log.d("App", msg)
}

// 4. Module for things Hilt can't build itself
@Module
@InstallIn(SingletonComponent::class)  // scope = whole app
object NetworkModule {
  @Provides @Singleton
  fun provideRetrofit(): Retrofit = Retrofit.Builder()
    .baseUrl("https://api.example.com")
    .addConverterFactory(GsonConverterFactory.create())
    .build()

  @Provides @Singleton
  fun provideUserApi(retrofit: Retrofit): UserApi = retrofit.create(UserApi::class.java)
}

@Module
@InstallIn(SingletonComponent::class)
object DatabaseModule {
  @Provides @Singleton
  fun provideDb(@ApplicationContext app: Context): AppDb =
    Room.databaseBuilder(app, AppDb::class.java, "app.db").build()

  @Provides fun provideUserDao(db: AppDb): UserDao = db.userDao()
}

@Module
@InstallIn(SingletonComponent::class)
abstract class BindingsModule {
  @Binds
  abstract fun bindLogService(impl: LogServiceImpl): LogService  // interface тЖТ impl
}

// 5. ViewModel тАФ Hilt provides its constructor deps
@HiltViewModel
class HomeViewModel @Inject constructor(
  private val repo: UserRepository,
  private val log: LogService,
) : ViewModel() {
  fun refresh() { viewModelScope.launch { repo.refresh(); log.log("refreshed") } }
}

// 6. Fragment тАФ mark @AndroidEntryPoint to receive injected VM
@AndroidEntryPoint
class HomeFragment : Fragment() {
  private val vm: HomeViewModel by viewModels()   // Hilt uses its own factory here

  override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
    super.onViewCreated(view, savedInstanceState)
    vm.refresh()
  }
}

// That's the whole graph. Hilt writes the wiring at compile time.
// You never write `UserRepository(dao, api)` by hand anywhere.

